method.description:
Will wait for [param signal] emission for a [param max_wait] amount of seconds.
This returns [signal timeout], the return value will be true if the signal was emitted, false if [param max_wait] was reached.
[codeblock]
var success = await wait_for_signal(player.respawned, 2, "Player should respawn within 2 second")
if success:
    pass_test("Player repawned within 2 seconds")
else:
    fail_test("Player respawn fail")
[/codeblock]
